export function getHexagramMnemonic(id) {
	const hid = Math.max(1, Math.min(64, Number(id) || 1))
	return HEXAGRAM_MNEMONICS[hid] || ''
}

/** 爻位名：自下而上 index 0–5 */
const LINE_POS_NAMES = ['初爻', '二爻', '三爻', '四爻', '五爻', '上爻']

export function formatMovingLinePositions(movingIndexes) {
	if (!movingIndexes || !movingIndexes.length) return ''
	return movingIndexes
		.map((i) => (i >= 0 && i < 6 ? LINE_POS_NAMES[i] : ''))
		.filter(Boolean)
		.join('、')
}

