function buildChangedHexagramNote(mainId, changedKwId, movingIndexes) {
	const movingText = formatMovingLinePositions(movingIndexes)
	if (changedKwId == null || changedKwId < 1 || changedKwId > 64) {
		return {
			hasChanged: false,
			changedTitle: '变卦说明',
			changedLead:
				'老阴（六）、老阳（九）为动爻；若六爻皆为少阴（八）、少阳（七），则爻象不动，传统上不设变卦。',
			changedBody:
				'此时宜以本卦意象与下方各方向参考为主，侧重当下处境与可执行的分寸；若日后出现动爻，再参变卦看事态推移。',
		}
	}
	const cid = Math.max(1, Math.min(64, changedKwId))
	const chName = HEXAGRAM_NAMES[cid]
	const chMn = HEXAGRAM_MNEMONICS[cid] || ''
	const chBase = HEXAGRAM_COPY[cid] || HEXAGRAM_COPY[1]
	const chDetail = HEXAGRAM_DETAIL[cid] || ''
	const moveHint = movingText
		? `本次动爻在：${movingText}（老阴变阳、老阳变阴）。`
		: '动爻已按古法化出变卦。'
	const lead = `${moveHint}变卦为《${chName}》（口诀：${chMn}），多用来参考「变动之后的事态倾向、心态与相处方式将如何偏移」，可与本卦对照阅读，而非简单以吉凶断之。`
	const body = `变卦意象摘要：${chBase.summary} ${chDetail.slice(0, 160)}${chDetail.length > 160 ? '…' : ''}`
	return {
		hasChanged: true,
		changedTitle: `变卦：${chName}`,
		changedLead: lead,
		changedBody: body,
	}
}

export function keyFromStaticBits(bits) {
	let k = 0
	for (let i = 0; i < 6; i++) {
		if (bits[i]) k |= 1 << i
	}
	return k
}

/** 由 6/7/8/9 自下而上得到阴阳爻（老阴老阳仍按阴阳画本卦） */
export function staticBitsFromLineValues(lines) {
	return lines.map((v) => (v === 7 || v === 9 ? 1 : 0))
}

export function kingWenIdFromStaticBits(bits) {
	return KW_KEY_MAP[keyFromStaticBits(bits)]
}

/** 变卦：老阴变阳、老阳变阴，静爻不变 */
export function flipMovingLines(staticBits, lineValues) {
	const next = staticBits.slice()
	for (let i = 0; i < 6; i++) {
		const v = lineValues[i]
		if (v === 6) next[i] = 1
		else if (v === 9) next[i] = 0
	}
	return next
}

