function buildReferenceBlock(base, pack) {
	return [
		`总述：${base.summary}`,
		`${base.career} ${REF_DIRECTION_EXTRA.career}`,
		`${base.love} ${REF_DIRECTION_EXTRA.love}`,
		`${pack.travel} ${REF_DIRECTION_EXTRA.travel}`,
		`${pack.decision} ${REF_DIRECTION_EXTRA.decision}`,
	].join('\n\n')
}

/**
 * @param {number} id 本卦 1–64
 * @param {{ changedKwId?: number | null, movingIndexes?: number[], skipChangedNote?: boolean }} [opts]
 *        skipChangedNote：卦单页浏览为 true，不返回变卦说明字段
 */
export function getHexagramCopy(id, opts) {
	const hid = Math.max(1, Math.min(64, id || 1))
	const base = HEXAGRAM_COPY[hid] || HEXAGRAM_COPY[1]
	const idx = hid - 1
	const pack = DIRECTION_ROTATIONS[idx % DIRECTION_ROTATIONS.length]
	const detail = HEXAGRAM_DETAIL[hid] || ''
	const o = opts || {}
	const changed =
		o.skipChangedNote === true
			? null
			: buildChangedHexagramNote(hid, o.changedKwId ?? null, o.movingIndexes)
	const referenceBlock = buildReferenceBlock(base, pack)
	return {
		summary: base.summary,
		detail,
		career: base.career,
		love: base.love,
		travel: pack.travel,
		decision: pack.decision,
		referenceBlock,
		closing: base.closing,
		mnemonic: HEXAGRAM_MNEMONICS[hid] || '',
		changedTitle: changed ? changed.changedTitle : '',
		changedLead: changed ? changed.changedLead : '',
		changedBody: changed ? changed.changedBody : '',
		hasChangedHexagram: changed ? changed.hasChanged : false,
	}
}
